// sdkUpdate patches the supplied resource in the backend AWS service API and
// returns a new resource with updated fields.
func (rm *resourceManager) sdkUpdate(
	ctx context.Context,
	desired *resource,
	latest *resource,
	delta *ackcompare.Delta,
) (updated *resource, err error) {
	rlog := ackrtlog.FromContext(ctx)
	exit := rlog.Trace("rm.sdkUpdate")
	defer func() {
		exit(err)
	}()

	if delta.DifferentAt("Spec.Tags") {
		err := rm.syncTags(
			ctx,
			latest,
			desired,
		)
		if err != nil {
			return nil, err
		}
	}
	if !delta.DifferentExcept("Spec.Tags") {
		return desired, nil
	}
	input, err := rm.newUpdateRequestPayload(ctx, desired, delta)
	if err != nil {
		return nil, err
	}

	var resp *svcsdk.UpdateDataSourceOutput
	_ = resp
	resp, err = rm.sdkapi.UpdateDataSource(ctx, input)
	rm.metrics.RecordAPICall("UPDATE", "UpdateDataSource", err)
	if err != nil {
		return nil, err
	}
	// Merge in the information we read from the API call above to the copy of
	// the original Kubernetes object we passed to the function
	ko := desired.ko.DeepCopy()

	if ko.Status.ACKResourceMetadata == nil {
		ko.Status.ACKResourceMetadata = &ackv1alpha1.ResourceMetadata{}
	}
	if resp.Arn != nil {
		arn := ackv1alpha1.AWSResourceName(*resp.Arn)
		ko.Status.ACKResourceMetadata.ARN = &arn
	}
	if resp.DataSourceId != nil {
		ko.Spec.DataSourceID = resp.DataSourceId
	} else {
		ko.Spec.DataSourceID = nil
	}
	if resp.RequestId != nil {
		ko.Status.RequestID = resp.RequestId
	} else {
		ko.Status.RequestID = nil
	}
	statusCopy := int64(resp.Status)
	ko.Status.Status = &statusCopy

	rm.setStatusDefaults(ko)
	return &resource{ko}, nil
}

